window.marked={parse:function(s){function e(t){return String(t||"").replace(/[&<>"']/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c]})}var out=[],list=null;String(s||"").split(/\r?\n/).forEach(function(line){var h=line.match(/^(#{1,3})\s+(.*)$/),li=line.match(/^[-*]\s+(.*)$/);if(h){if(list){out.push("</ul>");list=null}out.push("<h"+h[1].length+">"+e(h[2])+"</h"+h[1].length+">")}else if(li){if(!list){out.push("<ul>");list=true}out.push("<li>"+e(li[1])+"</li>")}else if(line.trim()){if(list){out.push("</ul>");list=null}out.push("<p>"+e(line)+"</p>")}else if(list){out.push("</ul>");list=null}});if(list)out.push("</ul>");return out.join("")}};
